        case 'lt':
          boolData[i] = value < threshold ? 1 : 0;
          break;
        case 'gte':
          boolData[i] = value >= threshold ? 1 : 0;
          break;
        case 'lte':
          boolData[i] = value <= threshold ? 1 : 0;
          break;
        case 'eq':
          boolData[i] = value === threshold ? 1 : 0;
          break;
        case 'neq':
          boolData[i] = value !== threshold ? 1 : 0;
          break;
      }
    }

