import { DenseNeuroVol } from './DenseNeuroVol';
import { NeuroSpace } from '../geometry/NeuroSpace';
import { NumericType } from '../types';
import { AxisSet3D } from '../geometry/Axis';

/**
 * Interface for Label Map
 */
interface LabelMap {
  [clusterId: number]: string;
}

/**
 * ClusterVol
 *
 * Represents volumetric data where each voxel is assigned to a cluster ID.
 * Cluster IDs are stored directly in the data array, with 0 indicating background or no cluster.
 */
export class ClusteredNeuroVol extends DenseNeuroVol {
  private labelMap: LabelMap;
  private clusterIndices: Map<number, number[]>;
  private labelToId: Map<string, number>;

  constructor(
    space: NeuroSpace,
    data: Int32Array,
    labelMap: LabelMap = {}
  ) {
    super(space, Int32Array, data.length, data);

    const expectedLength = space.dim.reduce((a, b) => a * b, 1);
    if (data.length !== expectedLength) {
      throw new Error(`Data length (${data.length}) does not match expected volume size (${expectedLength}).`);
    }

    this.labelMap = labelMap;
    this.clusterIndices = new Map();
    this.labelToId = new Map();

    this.initializeMaps();
  }

  private initializeMaps(): void {
    const data = this.getData() as Int32Array;

    console.log("ClusteredNeuroVol.initializeMaps - Starting to process data array of length:", data.length);

    // First, let's count how many of each ID we have
    const idCounts = new Map<number, number>();
    for (let i = 0; i < data.length; i++) {
      const clusterId = data[i];
      if (clusterId !== 0) {
        idCounts.set(clusterId, (idCounts.get(clusterId) || 0) + 1);
      }
    }

    console.log("Unique cluster IDs found in data:", Array.from(idCounts.keys()).sort((a, b) => a - b));
    console.log("Number of unique non-zero IDs:", idCounts.size);

    // Check distribution of IDs
    const clusterIds = Array.from(idCounts.keys());
    const minId = Math.min(...clusterIds);
    const maxId = Math.max(...clusterIds);
    console.log(`ID range: ${minId} to ${maxId}`);

    // Check if our label map has entries for all found IDs
    const missingLabels = Array.from(idCounts.keys()).filter(id => !this.labelMap[id]);
    if (missingLabels.length > 0) {
      console.warn(`Warning: ${missingLabels.length} cluster IDs have no label in the labelMap:`, 
                   missingLabels.length > 10 ? 
                   missingLabels.slice(0, 10).join(', ') + '...' : 
                   missingLabels.join(', '));
    }

    // Now build the cluster indices map
    for (let i = 0; i < data.length; i++) {
      const clusterId = data[i];
      if (clusterId !== 0) {
        if (!this.clusterIndices.has(clusterId)) {
          this.clusterIndices.set(clusterId, []);
        }
        this.clusterIndices.get(clusterId)!.push(i);
      }
    }

    console.log("ClusterIndices map size:", this.clusterIndices.size);

    // Verify clusterIndices content
    const clusterKeys = Array.from(this.clusterIndices.keys()).sort((a, b) => a - b);
    console.log("Cluster keys in clusterIndices:", 
               clusterKeys.length > 20 ? 
               clusterKeys.slice(0, 5).join(', ') + '...' + clusterKeys.slice(-5).join(', ') : 
               clusterKeys.join(', '));

    // Set up the label to ID mapping
    for (const [id, label] of Object.entries(this.labelMap)) {
      this.labelToId.set(label, parseInt(id));
    }

    console.log("labelToId map size:", this.labelToId.size);
  }

  /**
   * Returns the number of unique clusters, excluding background (cluster ID 0).
   */
  public numClusters(): number {
    return this.clusterIndices.size;
  }

  public getLabelMap(): LabelMap {
    return this.labelMap;
  }

  /**
   * Finds the linear indices associated with a given cluster ID.
   * @param idOrLabel - The cluster ID or label to search for.
   * @returns An array of linear indices where the cluster ID is found.
   */
  public getClusterIndices(idOrLabel: number | string): number[] | undefined {
    let id: number;
    if (typeof idOrLabel === 'string') {
      id = this.getClusterId(idOrLabel) || 0;
    } else {
      id = idOrLabel;
    }
    return this.clusterIndices.get(id);
  }

  /**
   * Finds the coordinates associated with a given cluster ID.
   * @param clusterId - The cluster ID to search for.
   * @returns An array of coordinates where the cluster ID is found.
   */
  public getClusterCoords(idOrLabel: number | string): number[][] | undefined {
    const indices = this.getClusterIndices(idOrLabel);
    return indices?.map(index => this.space.indexToGrid(index));
  }

  /**
   * Finds the label associated with a given cluster ID.
   * @param clusterId - The cluster ID to search for.
   * @returns The label associated with the cluster ID, or undefined if not found.
   */
  public getClusterLabel(id: number): string | undefined {
    return this.labelMap[id];
  }

  /**
   * Finds the cluster ID associated with a given label.
   * @param label - The label to search for.
   * @returns The cluster ID associated with the label, or undefined if not found.
   */
  public getClusterId(label: string): number | undefined {
    return this.labelToId.get(label);
  }

  /**
   * Returns an array of all cluster IDs.
   */
  public getClusterIds(): number[] {
    return Array.from(this.clusterIndices.keys());
  }

  /**
   * Returns an array of all cluster labels.
   */
  public getClusterLabels(): string[] {
    return Object.values(this.labelMap);
  }

  /**
   * Override getRange to return a range that's appropriate for cluster data.
   * Since cluster IDs are meaningful identifiers rather than continuous values,
   * we return a range from 0 to the maximum cluster ID found in the data.
   * This is more useful for visualization than the raw data min/max.
   */
  public getRange(): [number, number] {
    // Get all cluster IDs from the map populated during initialization
    const clusterIds = this.getClusterIds();

    if (clusterIds.length === 0) {
      console.log("No cluster IDs found, returning [0,0]");
      return [0, 0]; // No clusters
    }

    // Get the maximum cluster ID (exclude 0 which is typically background)
    const nonZeroIds = clusterIds.filter(id => id > 0);

    if (nonZeroIds.length === 0) {
      console.log("No non-zero cluster IDs found, returning [0,0]");
      return [0, 0]; // Only background
    }

    const maxId = Math.max(...nonZeroIds);
    console.log(`Determined cluster range from data: [0, ${maxId}]`);

    // Return range from 0 to max cluster ID
    return [0, maxId];
  }

  public getSliceTypedArrayType(): NumericType {
    return 'int32';
  }

  public getDataConstructor(): new (length: number) => Int32Array {
    return Int32Array;
  }

  /**
   * Displays information about the ClusterVol instance.
   */
  public show(): void {
    console.log('ClusterVol');
    console.log(`  Dimension      : ${this.space.dim.join(' x ')}`);
    console.log(`  Spacing        : ${this.space.spacing.join(' x ')}`);
    console.log(`  Origin         : ${this.space.origin.join(' x ')}`);
    console.log(`  Axes           : ${this.space.axes.toString()}`);
    console.log(`  Num Clusters   : ${this.numClusters()}`);
    if (Object.keys(this.labelMap).length > 0) {
      console.log('  Cluster Labels :');
      for (const [id, label] of Object.entries(this.labelMap)) {
        console.log(`    Cluster ${id}: ${label}`);
      }
    }
  }
}

