    if (!space) {
      const maxCoords = [0, 0, 0];
      for (const coord of coords) {
        maxCoords[0] = Math.max(maxCoords[0], coord[0] + 1);
        maxCoords[1] = Math.max(maxCoords[1], coord[1] + 1);
