    return `BigNeuroVec
  Type      : BigNeuroVec (memory-mapped)
  Dimension : ${this.shape.join(' X ')}
  Spacing   : ${this.space.spacing.join(' X ')}
  Origin    : ${this.space.origin.join(', ')}
  Filename  : ${this.filename}
  Mode      : ${this.mode}`;
  }
