  private _shape: number[];
  private _dtype: string;
  private itemSize: number;
  private totalSize: number;

  constructor(
    filename: string,
    dtype: string = 'float32',
    mode: string = 'r+',
    shape?: number[],
    order: string = 'C'
  ) {
    this._dtype = dtype;
    this._shape = shape || [];

    // Determine item size based on dtype
    switch (dtype) {
      case 'float32':
        this.itemSize = 4;
        break;
      case 'float64':
        this.itemSize = 8;
        break;
      case 'int32':
        this.itemSize = 4;
        break;
      case 'uint8':
