    if (mode === 'w+' || !fs.existsSync(filename)) {
      // Create new file
      this.fd = fs.openSync(filename, 'w+');
      if (this.totalSize > 0) {
        // Allocate space
        fs.ftruncateSync(this.fd, this.totalSize);
