  }

  get dim(): number[] {
    return this._data.shape;
  }

  get shape(): number[] {
    return this._data.shape;
  }

  get spacing(): number[] {
    return this.space.spacing;
  }

  get origin(): number[] {
    return this.space.origin;
  }

  /**
   * Get volume at time point t
   */
  getVolume(t: number): NeuroVol {
