   * Get time series at voxel (i, j, k)
   */
  getSeries(i: number, j: number, k: number): number[] {
    const series: number[] = [];
    for (let t = 0; t < this.shape[0]; t++) {
      series.push(this.getAt(t, i, j, k));
    }
    return series;
  }

  /**
   * Get all data (loads into memory)
   */
  getData(): TypedArray {
