      const space = new NeuroSpace(shape, [1, 1, 1, 1], [0, 0, 0, 0]);
      const data = new Float32Array(10 * 5 * 5 * 5);
      const filename = path.join(tempDir, 'custom.dat');

      const vec = new BigNeuroVec(data, space, { filename });

