      const vols = vec.vols([0, 2, 4]);

      expect(vols.length).toBe(3);
      expect(vols[0].data[0]).toBe(0);
      expect(vols[1].data[0]).toBe(200);
      expect(vols[2].data[0]).toBe(400);
    });
  });

  describe('subVector', () => {
    it('should extract subset of time points', () => {
      const shape = [5, 2, 2, 2];
