        new NeuroSpace([2, 2, 2], [1, 1, 1], [0, 0, 0])
      );

      const vol2 = new DenseNeuroVol(
        new Float32Array(27),
        new NeuroSpace([3, 3, 3], [1, 1, 1], [0, 0, 0])
      );

      expect(() => bigNeuroVecSeq([vol1, vol2])).toThrow('Volume 1 has inconsistent shape');
