      expect(subset.getAt(0, 0, 0, 1)).toBe(30);
    });
  });

  describe('chunk processing', () => {
    it('should process data in chunks', () => {
      const shape = [100, 2, 2, 2];
      const space = new NeuroSpace(shape, [1, 1, 1, 1], [0, 0, 0, 0]);
      const data = new Float32Array(100 * 2 * 2 * 2);

