    13→/**
    14→ * Read a NIfTI file and return a DenseNeuroVol object.
    15→ * @param {string | ArrayBuffer} input - The path to the NIfTI file or an ArrayBuffer.
    16→ * @returns {Promise<DenseNeuroVol>} A promise that resolves to a DenseNeuroVol object.
    17→ */
    18→export async function read_vol(input: string | ArrayBuffer): Promise<NeuroVol> {
    19→  try {
    20→    let buffer: ArrayBuffer;
    21→
    22→    if (typeof input === 'string') {
    23→      console.log('Reading file:', input);
    24→      const data = await fs.readFile(input);
    25→      console.log('File read successfully. Size:', data.length, 'bytes');
    26→      buffer = data.buffer;
    27→    } else {
    28→      console.log('Using provided ArrayBuffer');
    29→      buffer = input;
    30→    }
    31→
    32→    if (nifti.isCompressed(buffer)) {
    33→      console.log('File is compressed. Decompressing...');
    34→      buffer = nifti.decompress(buffer);
    35→      console.log('Decompression complete. New size:', buffer.byteLength, 'bytes');
    36→    }
    37→
    38→    if (!nifti.isNIFTI(buffer)) {
    39→      throw new Error('The file is not a valid NIfTI file.');
    40→    }
    41→
    42→    console.log('Reading NIfTI header...');
    43→    const header = nifti.readHeader(buffer);
    44→    if (!header) {
    45→      throw new Error('NIfTI header is null or undefined');
    46→    }
    47→    console.log('Header read successfully:', header);
    48→
    49→    if (!header.dims || header.dims.length < 4) {
    50→      throw new Error('Invalid header dimensions');
    51→    }
    52→
    53→    if (header.dims[0] !== 3) {
    54→      throw new Error(`The NIfTI file must contain a 3D image. Found ${header.dims[0]}D image.`);
    55→    }
    56→
    57→    console.log('Reading image data...');
    58→    const imageBuffer: ArrayBuffer = nifti.readImage(header, buffer);
    59→    const image: Uint8Array = new Uint8Array(imageBuffer);
    60→    console.log('Image data read successfully. Size:', image.byteLength);
    61→
    62→    const dim = Array.from(header.dims.slice(1, 4));
    63→    const spacing = Array.from(header.pixDims.slice(1, 4));
    64→    const origin: [number, number, number] = [header.affine[0][3], header.affine[1][3], header.affine[2][3]];
    65→
    66→    console.log('Dimensions:', dim);
    67→    console.log('Spacing:', spacing);
    68→    console.log('Origin:', origin);
    69→
    70→    const affine = new Matrix(header.affine);
    71→
    72→    console.log('Affine matrix:', affine.to2DArray());
    73→
    74→    const orientation = nearestAnatomy(affine);
    75→    console.log('Orientation:', orientation);
    76→
    77→    const space = new NeuroSpace(
    78→      dim,
    79→      spacing,
    80→      origin,
    81→      orientation,
    82→      affine
    83→    );
    84→
    85→    console.log('NeuroSpace created successfully');
    86→
    87→    // Choose the appropriate TypedArray based on the datatype
    88→    let dataType: 'int8' | 'uint8' | 'int16' | 'uint16' | 'int32' | 'uint32' | 'float32' | 'float64';
    89→    let TypedArray: TypedArrayConstructor;
    90→    switch (header.datatypeCode) {
    91→      case nifti.NIFTI1.TYPE_INT8: dataType = 'int8'; TypedArray = Int8Array; break;
    92→      case nifti.NIFTI1.TYPE_UINT8: dataType = 'uint8'; TypedArray = Uint8Array; break;
    93→      case nifti.NIFTI1.TYPE_INT16: dataType = 'int16'; TypedArray = Int16Array; break;
    94→      case nifti.NIFTI1.TYPE_UINT16: dataType = 'uint16'; TypedArray = Uint16Array; break;
    95→      case nifti.NIFTI1.TYPE_INT32: dataType = 'int32'; TypedArray = Int32Array; break;
    96→      case nifti.NIFTI1.TYPE_UINT32: dataType = 'uint32'; TypedArray = Uint32Array; break;
    97→      case nifti.NIFTI1.TYPE_FLOAT32: dataType = 'float32'; TypedArray = Float32Array; break;
    98→      case nifti.NIFTI1.TYPE_FLOAT64: dataType = 'float64'; TypedArray = Float64Array; break;
    99→      default: throw new Error(`Unsupported data type: ${header.datatypeCode}`);
   100→    }
   101→
   102→    // Reinterpret the Uint8Array buffer as the desired TypedArray
   103→    const typedImage = new TypedArray(
   104→      image.buffer,
   105→      image.byteOffset,
   106→      image.byteLength / (header.numBitsPerVoxel / 8) // Fixed line
   107→    );
   108→
   109→    // Check if the data length matches the expected length
   110→    const expectedLength = space.dim[0] * space.dim[1] * space.dim[2];
