   132→/**
   133→ * Writes a NeuroVol instance to a NIFTI file.
   134→ * @param vol - The NeuroVol instance to write.
   135→ * @param filePath - The file path to save the NIFTI file.
   136→ */
   137→export async function write_vol(vol: NeuroVol, filePath: string): Promise<void> {
   138→  try {
   139→    const space = vol.space;
   140→    const dim = space.dim;
   141→    const spacing = space.spacing;
   142→    const origin = space.origin;
   143→
   144→    // Create a buffer for the NIFTI header (348 bytes)
   145→    const headerBuffer = Buffer.alloc(348);
