   150→    // Set sizeof_hdr (int32), offset 0
   151→    headerView.setInt32(0, 348, true); // true for little-endian
   152→
   153→    // data_type (char[10]), offset 4 - unused, can leave as zeros
   154→
   155→    // db_name (char[18]), offset 14 - unused
   156→
   157→    // extents (int32), offset 32 - unused
   158→
   159→    // session_error (int16), offset 36 - unused
   160→
   161→    // regular (char), offset 38 - unused
   162→
   163→    // dim_info (char), offset 39 - set to 0
   164→    headerView.setUint8(39, 0);
   165→
   166→    // Set dim (int16[8]), offset 40
   167→    for (let i = 0; i < 8; i++) {
   168→      let value = 0;
   169→      if (i === 0) {
   170→        value = dim.length;
   171→      } else if (i <= dim.length) {
   172→        value = dim[i - 1];
   173→      } else {
   174→        value = 1;
   175→      }
   176→      headerView.setInt16(40 + i * 2, value, true);
   177→    }
   178→
   179→    // intent_p1 (float32), offset 56
   180→    headerView.setFloat32(56, 0.0, true);
   181→
   182→    // intent_p2 (float32), offset 60
   183→    headerView.setFloat32(60, 0.0, true);
   184→
   185→    // intent_p3 (float32), offset 64
   186→    headerView.setFloat32(64, 0.0, true);
   187→
   188→    // intent_code (int16), offset 68
   189→    headerView.setInt16(68, 0, true);
   190→
   191→    // Set datatype (int16), offset 70
   192→    let datatypeCode: number;
   193→    let bitpix: number;
   194→    const dataType = vol.getDataConstructor().name;
   195→    switch (dataType) {
   196→      case 'Int8Array':
   197→        datatypeCode = 256; // NIFTI_TYPE_INT8
   198→        bitpix = 8;
   199→        break;
   200→      case 'Uint8Array':
   201→        datatypeCode = 2; // NIFTI_TYPE_UINT8
   202→        bitpix = 8;
   203→        break;
   204→      case 'Int16Array':
   205→        datatypeCode = 4; // NIFTI_TYPE_INT16
   206→        bitpix = 16;
   207→        break;
   208→      case 'Uint16Array':
   209→        datatypeCode = 512; // NIFTI_TYPE_UINT16
   210→        bitpix = 16;
   211→        break;
   212→      case 'Int32Array':
   213→        datatypeCode = 8; // NIFTI_TYPE_INT32
   214→        bitpix = 32;
   215→        break;
   216→      case 'Uint32Array':
   217→        datatypeCode = 768; // NIFTI_TYPE_UINT32
   218→        bitpix = 32;
   219→        break;
   220→      case 'Float32Array':
   221→        datatypeCode = 16; // NIFTI_TYPE_FLOAT32
   222→        bitpix = 32;
   223→        break;
   224→      case 'Float64Array':
   225→        datatypeCode = 64; // NIFTI_TYPE_FLOAT64
   226→        bitpix = 64;
   227→        break;
   228→      default:
   229→        throw new Error(`Unsupported data type: ${dataType}`);
   230→    }
   231→    headerView.setInt16(70, datatypeCode, true);
   232→
   233→    // Set bitpix (int16), offset 72
   234→    headerView.setInt16(72, bitpix, true);
   235→
   236→    // slice_start (int16), offset 74
   237→    headerView.setInt16(74, 0, true);
   238→
   239→    // pixdim (float32[8]), offset 76
   240→    // pixdim[0] is unused
   241→    headerView.setFloat32(76, 0.0, true);
   242→    for (let i = 0; i < 7; i++) {
   243→      let pixdimValue = 1.0;
   244→      if (i < spacing.length) {
   245→        pixdimValue = spacing[i];
   246→      }
   247→      headerView.setFloat32(76 + (i + 1) * 4, pixdimValue, true);
   248→    }
   249→
   250→    // vox_offset (float32), offset 108
   251→    headerView.setFloat32(108, 352.0, true); // data starts at byte 352
   252→
   253→    // scl_slope (float32), offset 112
   254→    headerView.setFloat32(112, 1.0, true);
   255→
   256→    // scl_inter (float32), offset 116
   257→    headerView.setFloat32(116, 0.0, true);
   258→
   259→    // slice_end (int16), offset 120
   260→    headerView.setInt16(120, 0, true);
   261→
   262→    // slice_code (char), offset 122
   263→    headerView.setUint8(122, 0);
   264→
   265→    // xyzt_units (char), offset 123
   266→    // Set to mm for spatial units
   267→    const NIFTI_UNITS_MM = 2;
   268→    headerView.setUint8(123, NIFTI_UNITS_MM);
   269→
   270→    // cal_max (float32), offset 124
   271→    headerView.setFloat32(124, 0.0, true);
   272→
   273→    // cal_min (float32), offset 128
   274→    headerView.setFloat32(128, 0.0, true);
   275→
   276→    // slice_duration (float32), offset 132
   277→    headerView.setFloat32(132, 0.0, true);
   278→
   279→    // toffset (float32), offset 136
   280→    headerView.setFloat32(136, 0.0, true);
   281→
   282→    // glmax (int32), offset 140
   283→    headerView.setInt32(140, 0, true);
   284→
   285→    // glmin (int32), offset 144
   286→    headerView.setInt32(144, 0, true);
   287→
