   290→    const descripBytes = Buffer.from(description, 'utf-8');
   291→    headerBuffer.set(descripBytes, 148);
   292→
   293→    // aux_file (char[24]), offset 228
   294→    // Leave as zeros
   295→
   296→    // qform_code (int16), offset 252
   297→    headerView.setInt16(252, 0, true);
