      const shape = [5, 4, 4, 4]; // 5 time points
      const space = new NeuroSpace(shape, [1, 1, 1, 1], [0, 0, 0, 0]);
      const data = new Float32Array(5 * 64);

      for (let i = 0; i < data.length; i++) {
