import { writeVol, readVol } from './src/io/io.js';
import { FloatNeuroVol } from './src/volume/DenseNeuroVol.js';
import { NeuroSpace } from './src/geometry/NeuroSpace.js';
import * as fs from 'fs/promises';
import * as path from 'path';

async function testCompressedFile() {
  console.log('Testing compressed file...');
  const tempDir = '/tmp/test_io_debug';
  await fs.mkdir(tempDir, { recursive: true });

  const space = new NeuroSpace([5, 5, 5], [1, 1, 1], [0, 0, 0]);
  const data = new Float32Array(125);
  for (let i = 0; i < 125; i++) {
    data[i] = i;
  }
  const vol = new FloatNeuroVol(space, data);

  const filePath = path.join(tempDir, 'test_compressed.nii.gz');

  try {
    // Write with compression
    console.log('Writing compressed file...');
    await writeVol(vol, filePath, { compress: true });

    // Check file
    const stats = await fs.stat(filePath);
    console.log('Compressed file size:', stats.size, 'bytes');

    // Read back
    console.log('Reading compressed file...');
    const readVol2 = await readVol(filePath);
    console.log('Read successful!');
    console.log('Dimensions:', readVol2.space.dim);
    console.log('First few values:', Array.from(readVol2.getData().slice(0, 5)));

    // Verify
    if (readVol2.space.dim[0] === 5 && readVol2.space.dim[1] === 5 && readVol2.space.dim[2] === 5) {
      console.log('✓ Dimensions match');
    } else {
      console.log('✗ Dimensions mismatch');
    }

    if (readVol2.getData()[0] === 0 && readVol2.getData()[1] === 1) {
      console.log('✓ Data values correct');
    } else {
      console.log('✗ Data values incorrect');
    }

  } catch (err) {
    console.error('Error:', err.message);
    console.error(err.stack);
  } finally {
    await fs.unlink(filePath).catch(() => {});
  }
}

// Run test
testCompressedFile().catch(console.error);

