      for (const level of uniqueLevels) {
        const levelValues: number[] = [];

        for (let t = 0; t < nVolumes; t++) {
          if (fac[t] === level) {
            levelValues.push(x.data[t * spatialSize + voxIdx]);
          }
        }

        if (levelValues.length > 0) {
