/**
 * Correlation and connectivity analysis for neuroimaging data
 */

import { NeuroVec } from '../vec/NeuroVec';
import { NeuroVol } from '../volume/NeuroVol';
import { FloatNeuroVol } from '../volume/DenseNeuroVol';
import { SparseNeuroVol } from '../sparse/SparseNeuroVol';
import { NeuroSpace } from '../geometry/NeuroSpace';
import { ValueError } from '../types';
import { ROI } from '../roi/ROI_base';

/**
 * Compute voxel-wise correlation between two time series.
 * 
 * @param x - First NeuroVec (4D data)
 * @param y - Second NeuroVec (4D data)
 * @returns NeuroVol containing correlation coefficients
 */
export function correlateVoxels(x: NeuroVec, y: NeuroVec): NeuroVol {
  // Check dimensions match
  if (!x.dim.every((d, i) => d === y.dim[i])) {
