 */
export function functionalConnectivity(
  data: NeuroVec,
  rois: ROI[]
): Float32Array {
  const nROIs = rois.length;
  const nTimepoints = data.dim[0];

  // Extract mean time series for each ROI
  const roiTimeSeries: Float32Array[] = [];

  for (const roi of rois) {
