/**
 * Compute Pearson correlation coefficient between two arrays.
 */
function pearsonCorrelation(x: Float32Array, y: Float32Array): number {
  if (x.length !== y.length) {
    throw new ValueError('Arrays must have same length');
  }

  const n = x.length;
  if (n === 0) return 0;

  // Compute means
  let meanX = 0;
  let meanY = 0;
  for (let i = 0; i < n; i++) {
    meanX += x[i];
    meanY += y[i];
  }
  meanX /= n;
  meanY /= n;

  // Compute correlation
  let covXY = 0;
  let varX = 0;
  let varY = 0;

  for (let i = 0; i < n; i++) {
    const dx = x[i] - meanX;
    const dy = y[i] - meanY;
    covXY += dx * dy;
    varX += dx * dx;
    varY += dy * dy;
  }

  if (varX === 0 || varY === 0) return 0;

  return covXY / Math.sqrt(varX * varY);
}

/**
 * Compute partial correlation controlling for confounds.
 * 
 * @param x - First time series
 * @param y - Second time series
 * @param confounds - Matrix of confound variables (time x variables)
 * @returns Partial correlation coefficient
 */
export function partialCorrelation(
  x: Float32Array,
  y: Float32Array,
  confounds: Float32Array[]
): number {
  // Regress out confounds from both x and y
  const xResidual = regressOut(x, confounds);
  const yResidual = regressOut(y, confounds);

  // Return correlation of residuals
  return pearsonCorrelation(xResidual, yResidual);
}

/**
 * Regress out confounds from a time series.
 */
function regressOut(y: Float32Array, confounds: Float32Array[]): Float32Array {
  const n = y.length;
  const p = confounds.length;

  if (p === 0) return new Float32Array(y);

  // Build design matrix X
  const X = new Float32Array(n * (p + 1));
  for (let i = 0; i < n; i++) {
    X[i * (p + 1)] = 1; // Intercept
    for (let j = 0; j < p; j++) {
      X[i * (p + 1) + j + 1] = confounds[j][i];
    }
  }

  // Compute (X'X)^-1 X'y using normal equations
  // This is a simplified version - for production use a proper linear algebra library
  const XtX = new Float32Array((p + 1) * (p + 1));
  const Xty = new Float32Array(p + 1);

  // Compute X'X and X'y
  for (let i = 0; i < p + 1; i++) {
    for (let j = 0; j < p + 1; j++) {
      let sum = 0;
      for (let k = 0; k < n; k++) {
        sum += X[k * (p + 1) + i] * X[k * (p + 1) + j];
      }
      XtX[i * (p + 1) + j] = sum;
    }

    let sum = 0;
    for (let k = 0; k < n; k++) {
      sum += X[k * (p + 1) + i] * y[k];
    }
    Xty[i] = sum;
  }

  // Solve for beta (simplified - assumes XtX is invertible)
  const beta = solveLinearSystem(XtX, Xty, p + 1);

  // Compute residuals
  const residuals = new Float32Array(n);
  for (let i = 0; i < n; i++) {
    let pred = 0;
    for (let j = 0; j < p + 1; j++) {
      pred += X[i * (p + 1) + j] * beta[j];
    }
    residuals[i] = y[i] - pred;
  }

  return residuals;
}

/**
 * Simple linear system solver using Gaussian elimination.
 * For production use, consider using a proper linear algebra library.
 */
function solveLinearSystem(A: Float32Array, b: Float32Array, n: number): Float32Array {
  // Create augmented matrix
  const aug = new Float32Array(n * (n + 1));
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n; j++) {
      aug[i * (n + 1) + j] = A[i * n + j];
    }
    aug[i * (n + 1) + n] = b[i];
  }

  // Forward elimination
  for (let i = 0; i < n; i++) {
    // Find pivot
    let maxRow = i;
    for (let k = i + 1; k < n; k++) {
      if (Math.abs(aug[k * (n + 1) + i]) > Math.abs(aug[maxRow * (n + 1) + i])) {
        maxRow = k;
      }
    }

    // Swap rows
    for (let k = 0; k < n + 1; k++) {
      const tmp = aug[i * (n + 1) + k];
      aug[i * (n + 1) + k] = aug[maxRow * (n + 1) + k];
      aug[maxRow * (n + 1) + k] = tmp;
    }

    // Eliminate column
    for (let k = i + 1; k < n; k++) {
      const factor = aug[k * (n + 1) + i] / aug[i * (n + 1) + i];
      for (let j = i; j < n + 1; j++) {
        aug[k * (n + 1) + j] -= factor * aug[i * (n + 1) + j];
      }
    }
  }

  // Back substitution
  const x = new Float32Array(n);
  for (let i = n - 1; i >= 0; i--) {
    x[i] = aug[i * (n + 1) + n];
    for (let j = i + 1; j < n; j++) {
      x[i] -= aug[i * (n + 1) + j] * x[j];
    }
    x[i] /= aug[i * (n + 1) + i];
  }

  return x;
}

