import { describe, it, expect, beforeEach } from 'vitest';
import {
  correlateVoxels,
  seedCorrelation,
  functionalConnectivity,
  partialCorrelation
} from '../src/stats/correlation';
import { NeuroSpace } from '../src/geometry/NeuroSpace';
import { DenseNeuroVec } from '../src/vec/NeuroVec';
import { FloatNeuroVol } from '../src/volume/DenseNeuroVol';
import { sphericalROI } from '../src/roi/ROI_factories';

describe('Correlation Analysis', () => {
  let space4d: NeuroSpace;
  let testVec1: DenseNeuroVec;
  let testVec2: DenseNeuroVec;

  beforeEach(() => {
    // Create 4D space: 10 timepoints, 5x5x5 spatial
    space4d = new NeuroSpace([10, 5, 5, 5], [1, 1, 1, 1], [0, 0, 0, 0]);

    // Create test vectors with known correlation patterns
    const data1 = new Float32Array(10 * 125);
    const data2 = new Float32Array(10 * 125);

    // Create patterns:
    // - Some voxels perfectly correlated
    // - Some voxels anti-correlated
    // - Some voxels uncorrelated
    for (let vox = 0; vox < 125; vox++) {
      for (let t = 0; t < 10; t++) {
        const timeValue = Math.sin(t * Math.PI / 5); // Sinusoidal pattern

        if (vox < 25) {
          // Perfect correlation
          data1[t * 125 + vox] = timeValue;
          data2[t * 125 + vox] = timeValue;
        } else if (vox < 50) {
          // Anti-correlation
          data1[t * 125 + vox] = timeValue;
          data2[t * 125 + vox] = -timeValue;
        } else if (vox < 75) {
          // No correlation (random)
          data1[t * 125 + vox] = Math.random() - 0.5;
          data2[t * 125 + vox] = Math.random() - 0.5;
        } else {
          // Partial correlation with noise
          data1[t * 125 + vox] = timeValue + (Math.random() - 0.5) * 0.5;
          data2[t * 125 + vox] = timeValue + (Math.random() - 0.5) * 0.5;
        }
      }
    }

    testVec1 = new DenseNeuroVec(data1, space4d);
    testVec2 = new DenseNeuroVec(data2, space4d);
  });

  describe('correlateVoxels', () => {
    it('should compute voxel-wise correlations', () => {
      const corrMap = correlateVoxels(testVec1, testVec2);

      expect(corrMap).toBeInstanceOf(FloatNeuroVol);
      expect(corrMap.space.dim).toEqual([5, 5, 5]);

      const corrData = corrMap.getData();

      // Check perfect correlation voxels
      expect(corrData[0]).toBeCloseTo(1.0, 2);
      expect(corrData[10]).toBeCloseTo(1.0, 2);

      // Check anti-correlation voxels
      expect(corrData[25]).toBeCloseTo(-1.0, 2);
      expect(corrData[30]).toBeCloseTo(-1.0, 2);

      // Check uncorrelated voxels (should be near 0)
      expect(Math.abs(corrData[50])).toBeLessThan(0.5);
      expect(Math.abs(corrData[60])).toBeLessThan(0.5);
    });

    it('should handle identical time series', () => {
      const corrMap = correlateVoxels(testVec1, testVec1);
      const corrData = corrMap.getData();

      // All correlations should be 1.0 (perfect self-correlation)
      for (let i = 0; i < corrData.length; i++) {
        expect(corrData[i]).toBeCloseTo(1.0, 5);
      }
    });

    it('should throw error for dimension mismatch', () => {
      const wrongSpace = new NeuroSpace([10, 3, 3, 3], [1, 1, 1, 1], [0, 0, 0, 0]);
      const wrongVec = new DenseNeuroVec(new Float32Array(10 * 27), wrongSpace);

      expect(() => correlateVoxels(testVec1, wrongVec)).toThrow('same dimensions');
    });
  });

  describe('seedCorrelation', () => {
    it('should compute correlation with single voxel seed', () => {
      const seed: [number, number, number] = [0, 0, 0];
      const corrMap = seedCorrelation(testVec1, seed);

      expect(corrMap).toBeInstanceOf(FloatNeuroVol);
      expect(corrMap.space.dim).toEqual([5, 5, 5]);

      const corrData = corrMap.getData();

      // Seed voxel should have perfect correlation with itself
      expect(corrData[0]).toBeCloseTo(1.0, 5);

      // Other voxels in same group should have high correlation
      expect(corrData[1]).toBeGreaterThan(0.9);
    });

    it('should compute correlation with ROI seed', () => {
      const space3d = new NeuroSpace([5, 5, 5], [1, 1, 1], [0, 0, 0]);
      const roi = sphericalROI([2, 2, 2], 1.5, space3d);

      const corrMap = seedCorrelation(testVec1, roi);

      expect(corrMap).toBeInstanceOf(FloatNeuroVol);

      // ROI voxels should have high correlation with the mean
      const roiCoords = roi.getCoordinates();
      const corrData = corrMap.getData();

      for (const coord of roiCoords) {
        const idx = space3d.gridToIndex(coord[0], coord[1], coord[2]);
        expect(corrData[idx]).toBeGreaterThan(0.5);
      }
    });

    it('should handle edge case seed locations', () => {
      const edgeSeed: [number, number, number] = [4, 4, 4]; // Corner voxel
      const corrMap = seedCorrelation(testVec1, edgeSeed);

      expect(corrMap).toBeInstanceOf(FloatNeuroVol);
      expect(corrMap.getData()[124]).toBeCloseTo(1.0, 5); // Last voxel
    });
  });

  describe('functionalConnectivity', () => {
    it('should compute ROI-to-ROI connectivity matrix', () => {
      const space3d = new NeuroSpace([5, 5, 5], [1, 1, 1], [0, 0, 0]);

      // Create ROIs in different correlation groups
      const roi1 = sphericalROI([1, 1, 1], 1, space3d); // In correlated region
      const roi2 = sphericalROI([1, 3, 1], 1, space3d); // Also in correlated region
      const roi3 = sphericalROI([3, 3, 3], 1, space3d); // In uncorrelated region

      const connMatrix = functionalConnectivity(testVec1, [roi1, roi2, roi3]);

      expect(connMatrix.length).toBe(9); // 3x3 matrix

      // Diagonal should be 1.0 (self-correlation)
      expect(connMatrix[0]).toBeCloseTo(1.0, 2); // roi1-roi1
      expect(connMatrix[4]).toBeCloseTo(1.0, 2); // roi2-roi2
      expect(connMatrix[8]).toBeCloseTo(1.0, 2); // roi3-roi3

      // ROIs 1 and 2 should be highly correlated (same region)
      expect(connMatrix[1]).toBeGreaterThan(0.8); // roi1-roi2
      expect(connMatrix[3]).toBeGreaterThan(0.8); // roi2-roi1

      // ROI 3 should have low correlation with others
      expect(Math.abs(connMatrix[2])).toBeLessThan(0.5); // roi1-roi3
      expect(Math.abs(connMatrix[5])).toBeLessThan(0.5); // roi2-roi3
    });

    it('should produce symmetric connectivity matrix', () => {
      const space3d = new NeuroSpace([5, 5, 5], [1, 1, 1], [0, 0, 0]);
      const rois = [
        sphericalROI([1, 1, 1], 1, space3d),
        sphericalROI([3, 3, 3], 1, space3d),
        sphericalROI([1, 3, 2], 1, space3d)
      ];

      const connMatrix = functionalConnectivity(testVec1, rois);

      // Check symmetry
      expect(connMatrix[1]).toBeCloseTo(connMatrix[3], 5); // [0,1] = [1,0]
      expect(connMatrix[2]).toBeCloseTo(connMatrix[6], 5); // [0,2] = [2,0]
      expect(connMatrix[5]).toBeCloseTo(connMatrix[7], 5); // [1,2] = [2,1]
    });

    it('should handle single ROI', () => {
      const space3d = new NeuroSpace([5, 5, 5], [1, 1, 1], [0, 0, 0]);
      const roi = sphericalROI([2, 2, 2], 1, space3d);

      const connMatrix = functionalConnectivity(testVec1, [roi]);

      expect(connMatrix.length).toBe(1);
      expect(connMatrix[0]).toBeCloseTo(1.0, 5); // Self-correlation
    });
  });

  describe('partialCorrelation', () => {
    it('should compute partial correlation controlling for confounds', () => {
      // Create time series with known relationships
      const n = 20;
      const x = new Float32Array(n);
      const y = new Float32Array(n);
      const confound = new Float32Array(n);

      // x and y are both related to confound
      for (let i = 0; i < n; i++) {
        confound[i] = i;
        x[i] = 2 * i + (Math.random() - 0.5);
        y[i] = 3 * i + (Math.random() - 0.5);
      }

      // Raw correlation should be high
      const rawData1 = new Float32Array(n);
      const rawData2 = new Float32Array(n);
      for (let i = 0; i < n; i++) {
        rawData1[i] = x[i];
        rawData2[i] = y[i];
      }

      // Partial correlation should be lower after removing confound
      const partialCorr = partialCorrelation(x, y, [confound]);

      expect(Math.abs(partialCorr)).toBeLessThan(0.5);
    });

    it('should handle multiple confounds', () => {
      const n = 30;
      const x = new Float32Array(n);
      const y = new Float32Array(n);
      const conf1 = new Float32Array(n);
      const conf2 = new Float32Array(n);

      // Create data with multiple confound relationships
      for (let i = 0; i < n; i++) {
        conf1[i] = Math.sin(i * 0.5);
        conf2[i] = Math.cos(i * 0.3);
        x[i] = conf1[i] + 0.5 * conf2[i] + (Math.random() - 0.5) * 0.2;
        y[i] = conf1[i] - 0.5 * conf2[i] + (Math.random() - 0.5) * 0.2;
      }

      const partialCorr = partialCorrelation(x, y, [conf1, conf2]);

      // After removing confounds, correlation should be near zero
      expect(Math.abs(partialCorr)).toBeLessThan(0.3);
    });

    it('should return original correlation with no confounds', () => {
      const x = new Float32Array([1, 2, 3, 4, 5]);
      const y = new Float32Array([2, 4, 6, 8, 10]);

      const partialCorr = partialCorrelation(x, y, []);

      // Perfect correlation should remain
      expect(partialCorr).toBeCloseTo(1.0, 5);
    });
  });
});

