      expect(cent[1]).toBe(0);
      expect(cent[2]).toBe(0);
    });

    it('should skip background label 0', () => {
      const data = new Float32Array([0, 0, 1, 1, 2, 2]);
      const labelMap = new Map<number, string>([
        [0, 'Background'],
        [1, 'Cluster1'],
