 * Compute searchlights in parallel using Web Workers
 */
function computeSearchlightsParallel(
  mask: LogicalNeuroVol,
  radius: number,
  indices: number[],
  nonzero: boolean,
  cores: number,
  onProgress?: (progress: number) => void
): ROIVolWindow[] {
  // For Node.js environment, we'll use a simple sequential implementation
  // For browser environment, this would use actual Web Workers

  // TODO: Implement actual Web Worker support for browser environments
  // For now, fall back to sequential processing
  console.warn('Web Worker support not yet implemented, falling back to sequential processing');

  const results: ROIVolWindow[] = [];
  for (let i = 0; i < indices.length; i++) {
    const centerIdx = nonzero ? indices[i] : i;
    const centerGrid = mask.space.indexToGrid(centerIdx);
    const roi = sphericalROI(centerGrid, radius, mask.space, mask);

    const window = new ROIVolWindow(
