}

/**
 * Compute searchlights in parallel using Web Workers
 */
async function computeSearchlightsParallel(
  mask: LogicalNeuroVol,
  radius: number,
  indices: number[],
  nonzero: boolean,
  cores: number,
  onProgress?: (progress: number) => void
