    const results = await pool.computeSearchlights(
      Array.from({ length: indices.length }, (_, i) => i)
    );

    // Convert results to ROIVolWindow objects
    return results.map(result => {
      const space = new NeuroSpace(
        result.space.dim,
        result.space.spacing,
        result.space.origin
