      roi.space,
      roi.data,
      roi.coords,
      centerIdx,
      0
    );
    results.push(window);
    onProgress?.(i / indices.length);
  }
  onProgress?.(1.0);

  return results;
}

/**
 * Compute coordinates in parallel using Web Workers
 */
async function computeCoordsParallel(
  mask: LogicalNeuroVol,
  radius: number,
  indices: number[],
  nonzero: boolean,
  cores: number
