    const centerGrid = logicalMask.space.indexToGrid(centerIdx);

    // Ensure centerGrid is a 3-element array
    const centerGrid3D: [number, number, number] = [
      centerGrid[0] || 0,
      centerGrid[1] || 0,
      centerGrid[2] || 0
    ];

    // Create spherical ROI around this center
    const roi = sphericalROI(centerGrid3D, radius, logicalMask.space, logicalMask);

    // Create ROIVolWindow
    const window = new ROIVolWindow(
      roi.space,
      roi.data,
      roi.coords,
      centerIdx,
      0
    );
    results.push(window);
  }

  return results;
}

/**
