    64→/**
    65→ * OrthogonalImageViewer manages three simultaneous SliceViewers (Axial, Coronal, Sagittal),
    66→ * each displaying a different orientation of the same data. The user can interact with
    67→ * any sub-view to change the shared coordinate, updating the other sub-views in sync.
    68→ *
    69→ * All the sub-viewers are arranged in a grid layout. The class handles:
    70→ *   - Creating the DOM elements for each view.
    71→ *   - Initializing and disposing the sub-viewers.
    72→ *   - Synchronizing the position (currentCoord) among the sub-viewers.
    73→ *   - Handling window resize events and re-drawing each view.
    74→ *   - Reactively updating the sub-viewers if the user adjusts slice indices in any one viewer.
    75→ */
    76→export class OrthogonalImageViewer implements ViewerStateInfo {
    77→  /**
    78→   * The current 3D coordinate shared by all sub-viewers. 
    79→   * This is updated whenever one of the SliceViewers changes its currentCoord.
    80→   */
    81→  @observable public currentCoord: number[];
    82→
    83→  /**
