    89→    imageCoordinate: { x: number; y: number } | null;
    90→    volumeCoordinate: number[] | null;
    91→    worldCoordinate: number[] | null;
    92→  } = {
    93→    viewName: null,
    94→    imageCoordinate: null,
    95→    volumeCoordinate: null,
    96→    worldCoordinate: null
    97→  };
    98→
    99→  // The top-level parameters for container and layer.
   100→  private params: OrthogonalImageViewerParams;
   101→  private container: HTMLElement;
   102→  private imageLayer: ImageLayer;
   103→
   104→  // A dictionary of SliceViewers: keys are "axial", "coronal", "sagittal".
   105→  private sliceViewers: Record<ViewName, SliceViewer>;
   106→
   107→  // A dictionary of AxisSet3D for each standard orientation.
   108→  private axesSets: Record<ViewName, AxisSet3D>;
   109→
   110→  // Additional user-defined options like "showCrosshair" or "showSlider".
   111→  private options: OrthogonalImageViewerOptions;
   112→
   113→  // A dictionary of DOM elements (HTML divs) for each sub-view.
   114→  private viewDivs: Record<ViewName, HTMLElement> = {} as Record<ViewName, HTMLElement>;
   115→
   116→  // Bound method for handling container resize events.
   117→  private handleResizeBound = this.handleResize.bind(this);
   118→
   119→  // A collection of MobX disposers for cleaning up reactive side effects.
   120→  private disposers: IReactionDisposer[] = [];
   121→
   122→  /**
   123→   * Private constructor to force usage of the async factory method `.create()`.
   124→   * 
   125→   * @param params - The container, imageLayer, and optional settings.
   126→   */
