   147→    makeObservable(this);
   148→  }
   149→
   150→  /**
   151→   * Creates an OrthogonalImageViewer, asynchronously building its sub-viewers.
   152→   * 
   153→   * @param params - Contains the container HTMLElement, imageLayer, and viewer options.
   154→   * @returns A fully-initialized instance of OrthogonalImageViewer.
   155→   */
