   163→
   164→  /**
   165→   * Main async init routine that sets up the layout grid, creates each SliceViewer,
   166→   * and wires up MobX reactions.
   167→   */
   168→  private async initialize(): Promise<void> {
   169→    // 1) Create the layout DOM structure
