   171→
   172→    // 2) Instantiate each of the three sub-viewers
   173→    await this.initializeViewers();
   174→
   175→    // 3) Set up cross-view property syncing
   176→    this.setupReactions();
   177→
   178→    // 4) Perform initial sizing
   179→    this.handleResize();
   180→  }
   181→
   182→  /**
   183→   * Creates HTML divs for each orientation (axial, coronal, sagittal) inside a 2x2 CSS grid.
   184→   */
   185→  private async initializeLayout(): Promise<void> {
   186→    // Create sub-viewer divs
   187→    const axialDiv = document.createElement('div');
   188→    const coronalDiv = document.createElement('div');
   189→    const sagittalDiv = document.createElement('div');
   190→
   191→    // Define a style object to share across the sub-view divs
   192→    const viewStyle: Partial<CSSStyleDeclaration> = {
   193→      width: '100%',
   194→      height: '100%',
   195→      position: 'relative',
   196→      overflow: 'hidden',
   197→    };
   198→
   199→    // Apply the styles to each sub-view div
   200→    Object.assign(axialDiv.style, viewStyle);
   201→    Object.assign(coronalDiv.style, viewStyle);
   202→    Object.assign(sagittalDiv.style, viewStyle);
   203→
   204→    // Name each div for a CSS grid area
   205→    axialDiv.style.gridArea = 'axial';
   206→    coronalDiv.style.gridArea = 'coronal';
   207→    sagittalDiv.style.gridArea = 'sagittal';
   208→
   209→    // The container is turned into a grid layout with 2 rows × 2 columns.
   210→    // 
   211→    //  +--------------+--------------+
   212→    //  | axial (col1) | coronal (col2)
   213→    //  +--------------+--------------+
   214→    //  | axial (col1) | sagittal(col2)
   215→    //  +--------------+--------------+
   216→    //
   217→    //  So axial is tall, occupying left side in both rows, while coronal/sagittal share the top/bottom of right side.
   218→    const viewerContainer = this.container;
   219→    viewerContainer.style.display = 'grid';
   220→    viewerContainer.style.gridTemplateAreas = `
   221→      "axial coronal"
   222→      "axial sagittal"
   223→    `;
   224→    viewerContainer.style.gridTemplateColumns = '1fr 1fr';
   225→    viewerContainer.style.gridTemplateRows = '1fr 1fr';
   226→    viewerContainer.style.gap = '2px';
   227→
   228→    // Add the new sub-view divs to the container
   229→    viewerContainer.appendChild(axialDiv);
   230→    viewerContainer.appendChild(coronalDiv);
   231→    viewerContainer.appendChild(sagittalDiv);
   232→
   233→    // Store references in a dictionary keyed by the ViewName enum
   234→    this.viewDivs = {
   235→      [ViewName.Axial]: axialDiv,
   236→      [ViewName.Coronal]: coronalDiv,
   237→      [ViewName.Sagittal]: sagittalDiv,
   238→    };
   239→  }
