   254→        showCrosshair: this.options.showCrosshair,
   255→        showSlider: this.options.showSlider,
   256→      });
   257→      this.sliceViewers[viewName] = viewer;
   258→
   259→      // Observe changes in each viewer's internal state
   260→      this.setupViewerReactions(viewName, viewer);
   261→
   262→      console.log(`${viewName} SliceViewer created.`);
   263→    });
   264→
   265→    // Wait for all three sub-viewers to be created
   266→    await Promise.all(creationPromises);
   267→
   268→    // After creation, set them all to the same initial currentCoord
   269→    this.setAllViewersPosition(this.currentCoord);
   270→  }
   271→
   272→  /**
   273→   * Sets up a global reaction so if our shared currentCoord changes, 
   274→   * all sub-viewers are updated to match.
   275→   */
   276→  private setupReactions(): void {
   277→    // Reaction: watch currentCoord in this OrthogonalImageViewer
   278→    // and call setAllViewersPosition() when it changes.
   279→    const coordDisposer = reaction(
   280→      () => this.currentCoord.slice(), // track changes by copying array
   281→      (coord) => {
   282→        console.log(`Ortho Current coord changed to ${coord}`);
   283→        this.setAllViewersPosition(coord);
   284→      }
   285→    );
   286→    this.disposers.push(coordDisposer);
   287→
   288→    
   289→  }
   290→
   291→  /**
   292→   * Sets up watchers on each sub-viewer so that if it changes coordinate or mouse
   293→   * state, we reflect that in the shared state here. This ensures that interacting
   294→   * with one view updates the others.
   295→   */
   296→  private setupViewerReactions(viewName: ViewName, viewer: SliceViewer): void {
   297→    // 1) Whenever the sub-viewer's model.currentCoord changes,
   298→    //    see if it's different from our shared currentCoord. If so, update ours.
   299→    const coordDisposer = reaction(
   300→      () => viewer.model.currentCoord.slice(),
   301→      (coord) => {
   302→        console.log(`${viewName} viewer current coord changed to ${coord}`);
   303→        if (!this.positionsAreEqual(this.currentCoord, coord)) {
   304→          //console.log(`${viewName} viewer current coord changed to ${coord}, updating shared currentCoord`);
   305→          this.setCurrentCoord(coord, viewName); // Update the global coordinate
   306→        } else {
   307→          //console.log(`${viewName} viewer current coord is the same as shared currentCoord, skipping`);
   308→        }
   309→      }
   310→    );
   311→    this.disposers.push(coordDisposer);
   312→
   313→    // 2) Watch for mouse state changes in the sub-viewer (image & volume coords).
   314→    const mouseImagePositionDisposer = reaction(
   315→      () => viewer.mouseImagePosition,
   316→      (imagePosition) => {
   317→        //console.log(`${viewName} mouse image position changed to`, imagePosition);
   318→        this.updateMouseState(viewName, imagePosition, viewer.mouseVolumeCoordinate, viewer.mouseWorldCoordinate);
   319→      }
   320→    );
   321→    this.disposers.push(mouseImagePositionDisposer);
   322→
   323→    const mouseVolumeCoordinateDisposer = reaction(
   324→      () => viewer.mouseVolumeCoordinate.slice(),
   325→      (volumeCoordinate) => {
   326→        //console.log(`${viewName} mouse volume coordinate changed to`, volumeCoordinate);
   327→        this.updateMouseState(viewName, viewer.mouseImagePosition, volumeCoordinate, viewer.mouseWorldCoordinate);
   328→      }
   329→    );
   330→    this.disposers.push(mouseVolumeCoordinateDisposer);
   331→
   332→    const mouseWorldDisposer = reaction(
   333→      () => viewer.mouseWorldCoordinate.slice(),  // or just viewer.mouseWorldCoordinate if it's always an array
   334→      (worldCoord) => {
   335→        //console.log(`${viewName} mouse worldCoord changed:`, worldCoord);
   336→        this.updateMouseState(
   337→          viewName,
   338→          viewer.mouseImagePosition,
   339→          viewer.mouseVolumeCoordinate,
   340→          worldCoord
   341→        );
   342→      }
   343→    );
   344→    this.disposers.push(mouseWorldDisposer);
   345→  }
