   347→  /**
   348→   * Writes a new shared currentCoord, typically after receiving a sub-viewer's updated coordinate.
   349→   * @param coord The newly updated coordinate from one sub-view.
   350→   * @param sourceView The name of the sub-view that triggered the change (if any).
   351→   */
   352→  @action
   353→  private setCurrentCoord(coord: number[], sourceView: ViewName): void {
   354→    console.log("shared coordinate updated to ", coord);
   355→    this.currentCoord = coord.slice();
   356→  }
