   358→  /**
   359→   * Checks if two coordinate arrays are identical.
   360→   */
   361→  private positionsAreEqual(coord1: number[], coord2: number[]): boolean {
   362→    if (coord1.length !== coord2.length) {
   363→      return false;
   364→    }
   365→    for (let i = 0; i < coord1.length; i++) {
