    27→   * @throws {Error} If `space.dim` is not 2-dimensional or `data.length` does not match `space.dim`.
    28→   */
    29→  constructor(space: NeuroSpace, data: TypedArray) {
    30→    if (space.dim.length !== 2) {
    31→      throw new Error('NeuroSpace for NeuroSlice must be 2-dimensional');
    32→    }
    33→
    34→    const expectedLength = space.dim[0] * space.dim[1];
    35→    if (data.length !== expectedLength) {
    36→      throw new Error('Data length does not match the dimensions specified in space');
    37→    }
    38→
    39→    this._space = space;
    40→    this.data = data;
    41→  }
