    85→   * @param i - x-coordinate
    86→   * @param j - y-coordinate
    87→   * @returns The pixel value.
    88→   * @throws {RangeError} If coordinates are out of bounds.
    89→   */
    90→  getAt(i: number, j: number): number {
    91→    const [nx, ny] = this.dim;
    92→    if (i < 0 || i >= nx || j < 0 || j >= ny) {
    93→      throw new RangeError('Coordinates out of bounds');
    94→    }
    95→    const index = j * nx + i;
    96→    return this.data[index];
    97→  }
    98→
    99→  /**
   100→   * Set a pixel value at specified coordinates.
   101→   * @param i - x-coordinate
   102→   * @param j - y-coordinate
   103→   * @param value - The value to set.
   104→   * @throws {RangeError} If coordinates are out of bounds.
   105→   */
   106→  setAt(i: number, j: number, value: number): void {
   107→    const [nx, ny] = this.dim;
   108→    if (i < 0 || i >= nx || j < 0 || j >= ny) {
   109→      throw new RangeError('Coordinates out of bounds');
   110→    }
   111→    const index = j * nx + i;
   112→    this.data[index] = value as any; // Type assertion since TypedArray elements are numbers
   113→  }
   114→
   115→  /**
   116→   * Get a row of the slice.
   117→   * @param j - y-coordinate of the row
   118→   * @returns The row data as the same TypedArray type.
   119→   * @throws {RangeError} If the row index is out of bounds.
   120→   */
   121→  getRow(j: number): TypedArray {
   122→    const [nx, ny] = this.dim;
   123→    if (j < 0 || j >= ny) {
   124→      throw new RangeError('Row index out of bounds');
   125→    }
   126→    return this.data.slice(j * nx, (j + 1) * nx);
   127→  }
   128→
   129→  /**
   130→   * Get a column of the slice.
   131→   * @param i - x-coordinate of the column
   132→   * @returns The column data as the same TypedArray type.
   133→   * @throws {RangeError} If the column index is out of bounds.
   134→   */
   135→  getColumn(i: number): TypedArray {
   136→    const [nx, ny] = this.dim;
   137→    if (i < 0 || i >= nx) {
   138→      throw new RangeError('Column index out of bounds');
   139→    }
   140→    const columnData = new (this.data.constructor as { new (length: number): TypedArray })(ny);
   141→    for (let j = 0; j < ny; j++) {
   142→      columnData[j] = this.data[j * nx + i];
   143→    }
   144→    return columnData;
   145→  }
   146→
