  vol: NeuroVol,
  sliceType: 'axial' | 'sagittal' | 'coronal',
  sliceIndex?: number
): [number[], number[]] {
  // Get volume bounds in world space
  const bounds = vol.space.bounds();
  const minBounds = [...bounds[0]];
  const maxBounds = [...bounds[1]];

  if (sliceIndex !== undefined) {
    // Get the axis for this slice type
    let axis: number;
    switch (sliceType) {
      case 'axial':
        axis = 2; // z-axis
        break;
      case 'sagittal':
        axis = 0; // x-axis
        break;
      case 'coronal':
        axis = 1; // y-axis
        break;
      default:
